body:
Input:

```mlir
firrtl.circuit "Test" {
  firrtl.module @Test() {
    %child_ref = firrtl.instance child @Child(in in: !firrtl.ref<uint<1>>)
    %send_ref = firrtl.instance send @send(out dest: !firrtl.ref<uint<1>>) 
    firrtl.strictconnect %child_ref, %send_ref : !firrtl.ref<uint<1>>
  }
  firrtl.module private @Child(in %in: !firrtl.ref<uint<1>>) {
    %x = firrtl.ref.resolve %in: !firrtl.ref<uint<1>>
    %sink = firrtl.instance sink @Sink(in sink: !firrtl.uint<1>)
    firrtl.strictconnect %sink, %x: !firrtl.uint<1>
  }
  firrtl.extmodule @Sink(in sink: !firrtl.uint<1>)
  firrtl.extmodule @Source(out source: !firrtl.uint<1>)

  firrtl.module private @send(out %dest: !firrtl.ref<uint<1>>) {
    %source = firrtl.instance source @Source(out source: !firrtl.uint<1>) 
    %ref_source = firrtl.ref.send %source: !firrtl.uint<1>
    firrtl.connect %dest, %ref_source : !firrtl.ref<uint<1>>, !firrtl.ref<uint<1>>
  }
}
```

Building with firtool, you get:

```verilog
// Generated by CIRCT 1.27.0g20230116_dd90916
module Test();	// ref_source.mlir:2:3
  Child child ();	// ref_source.mlir:3:18
  send send ();	// ref_source.mlir:4:17
endmodule

module Child();	// ref_source.mlir:7:3
  Sink sink (	// ref_source.mlir:9:13
    .sink (Test.send.source)	// ref_source.mlir:8:10, :10:5
  );
endmodule

// external module Sink

// external module Source

module send();	// ref_source.mlir:15:3
  wire _source_source;	// ref_source.mlir:16:15
  Source source (	// ref_source.mlir:16:15
    .source (_source_source)
  );
endmodule
```

The XMR points to the instance named "source", not the resulting port.

Looks like maybe we generate an XMR for the name of the operation defining the `ref.send` value, but haven't looked into it.
